INSERT INTO regular_expressions (name, pattern, description) VALUES ('3D', '(?<=\b[12]\d{3}\b).*\b((bluray|bd)?3d|sbs|half[ .-]ou|half[ .-]sbs)\b', 'Marqueurs 3D stéréoscopique (bluray3d, SBS, half-OU) après l’année dans le titre. Pourquoi : peu d’installations 3D actives — souvent malus sur les profils.');
INSERT INTO regular_expressions (name, pattern, description) VALUES ('AAC', '\bAAC(\b|\d)', 'AAC, alias Advanced Audio Coding (\bAAC puis fin de bloc ou suffixe numérique AAC5.1). Codec lossy léger très courant flux WEB télé et encodes partagés sur trackers français ; différent Dolby (Dolby Digital, DD+).');
INSERT INTO regular_expressions (name, pattern, description) VALUES ('AV1', '\b(AV1)\b', 'AV1 — détecté pour exclusion : nos profils FR appliquent -999999 (compatibilité TV / box / lecteurs domestiques).');
INSERT INTO regular_expressions (name, pattern, description) VALUES ('Basic HDR Formats', '(?:(?<=^(?!.*\b(HLG|PQ|SDR)(\b|\d)).*?)HDR)|\b(dv(?![ .](HLG|SDR))|dovi|dolby[ .]?vision)\b', 'Détecte la présence littérale HDR dans le titre (hors contextes parasites HLG / PQ / SDR combinés trompeusement), ou encore les marqueurs DV / Dolby Vision dans la même logique projet.');
INSERT INTO regular_expressions (name, pattern, description) VALUES ('DTS Basic', 'DTS[ .]?[1-9]', 'DTS suivi quasi immédiatement d’un chiffre de canal (DTS.5, DTS 5) : variante télégraphique ancienne télé/broadcast (pattern DTS[ .]?[1-9] projet Dictionarry).');
INSERT INTO regular_expressions (name, pattern, description) VALUES ('DTS-ES', '(?i)dts[-. ]?es\b', 'DTS-ES (Extended Surround) : extension matricielle 6.1/ES fréquentes vieux téléchargements DVD/Bluray Dolby Surround.');
INSERT INTO regular_expressions (name, pattern, description) VALUES ('DTS-HD HRA ES', 'dts[-. ]?(es|(hd[. ]?)?(hr|hi))', 'Couverture combinée DTS-ES et variantes high resolution (HR, HI) du DTS classique lorsque titreurs anciens mélangent abréviations ; aide les autres CF Dolby/DTS à s’exclure sans doublons.');
INSERT INTO regular_expressions (name, pattern, description) VALUES ('DTS-HD HRA', '(?i)dts[-. ]?(hd[. ]?)?(hra?|hi\b)', 'DTS-HD High Resolution (HRA, alias HI) : couche DTS « haute résolution » mais non lossless, intermédiaire entre DTS classique Core et MA.');
INSERT INTO regular_expressions (name, pattern, description) VALUES ('DTS-HD MA', '(?i)\b(dts[-_. ]?(ma|hd([-_. ]?ma)?|xll))(\b|\d)', 'DTS‑HD Master Audio : famille MA / DTS‑HD MA / XLL (sans perte) distincte du DTS:X et du DTS‑HRA. Très fréquent sur remux Blu-ray / UHD et certains flux WEB premium.');
INSERT INTO regular_expressions (name, pattern, description) VALUES ('DTS-X', '(?i)\b(dts[-_. :]?x)\b(?!\d)', 'DTS:X (« immersif objet ») hors variantes parasites numériques (\d), variantes typo dts.x / dts_x permissives suivant ancien tableau TRaSH.');
INSERT INTO regular_expressions (name, pattern, description) VALUES ('DTS', '\bDTS(\b|\d)', 'Core DTS (« DTS » générique hors extensions HD ou X) juste suivie canalisation numérique (ex DTS5, DTS.5) — format audio compressé ancien télé/broadcast léger remaster Blu-ray française.');
INSERT INTO regular_expressions (name, pattern, description) VALUES ('Dolby Digital +', '\bDD[P+]|\b(e[-_. ]?ac3)\b', 'Dolby Digital Plus (DD+, E‑AC‑3) : alias DDP ou e.ac3 (séparateurs ./_/espaces tolérés). Distinct du Dolby Digital « AC‑3 » classique (voir fichier Dolby Digital.yml du dossier regex).');
INSERT INTO regular_expressions (name, pattern, description) VALUES ('Dolby Digital', '\bDD[^a-z+]|(?<!e)ac3', 'Dolby Digital « classique » : alias DD (hors familles DD+) ou encore AC3 / ac3 selon motifs regex projet, distinct de E‑AC‑3 (Dolby Digital +) et des flux lossless Dolby.');
INSERT INTO regular_expressions (name, pattern, description) VALUES ('Dolby Vision (Without Fallback)', '(?<=^(?!.*(HDR|HULU|REMUX|BLURAY)).*?)\b(DV|Dovi|Dolby[- .]?V(ision)?)\b', 'Dolby Vision sans annonce évidente d’une couche HDR10/accompagnement classique (« fallback » HDR) lisible depuis le titre : évite DV « orphelin » mal typé hors contextes Hulu/Remux généralement garantissant double couche Dolby+HDR lorsqu…');
INSERT INTO regular_expressions (name, pattern, description) VALUES ('Dolby Vision', '(?i)\b(dv(?![ .](HLG|SDR))|dovi|dolby[ .]?vision)\b', 'Dolby Vision (« DV », DoVi, Dolby.Vision) : métadonnées dynamiques HDR sur scène/frame. Le motif évite DV accolé trivialement à HLG / SDR isolé (« (?![ .](HLG|SDR)) » après DV) pour ne pas confondre profils Dolby avec hybrides broadcast …');
INSERT INTO regular_expressions (name, pattern, description) VALUES ('FLAC', '\bFLAC(\b|\d)', 'FLAC sans perte annoncée sur la ligne release (FLAC, profils FLAC24, …). À distinguer du PCM/LPCM non compressés (PCM.yml).');
INSERT INTO regular_expressions (name, pattern, description) VALUES ('FR-Regex-4KLight', '(?i)\b4K[ ._-]?Light\b', 'Détecte le tag 4KLight (Bluray 4K UHD allégé, qualité visuelle préservée avec taille réduite). Référence sur la scène française privée, particulièrement les releases QTZ et BONBON réputées pour leur qualité d''encodage 4KLight.');
INSERT INTO regular_expressions (name, pattern, description) VALUES ('FR-Regex-Atmos-Bundle', '(?i)(?:\bATMOS\b|DDPA(\b|\d)|\bTrue[ .-]?HDA[ .-]?[57]\.1)', 'Regroupe les motifs officiels Atmos + variante BroadcastTheNet (TrueHD.A 5.1 / 7.1) pour un seul fichier projet — remplace Atmos et BTN Atmos.');
INSERT INTO regular_expressions (name, pattern, description) VALUES ('FR-Regex-Blockers', '(?i)\b(k0RE|Wawacity|YIFY|YTS|RARBG|FGT|GalaxyRG|GalaxyTV|MeGusta|ETRG|ION10|TGx|WAVES|NoGRP|NoGroup|ATTKC|SUJAIDR|LAMA|TimeStrike|Pahe|TBS|EVO|RMTeam|ETHEL|Telly|playSD|playWEB)\b|\b(NVENC|QSV|AMF)\b|(?=.*\b(REMUX|BDMV|ISO)\b)(?=.*\b(x26[45]|h26[45])\b)', 'Liste noire scène française privée — groupes bannis internationaux à basse réputation (YIFY, FGT, GalaxyRG, etc.), encodeurs GPU interdits (NVENC, QSV, AMF) et incohérences techniques majeures (REMUX / BDMV / ISO combinés à…');
INSERT INTO regular_expressions (name, pattern, description) VALUES ('FR-Regex-HDLight', '(?i)\bHDLight\b', 'Détecte le tag HDLight (Bluray rip allégé, qualité réduite mais HD). Convention typique de la scène française privée pour économiser bande passante tout en conservant 1080p / 720p.');
INSERT INTO regular_expressions (name, pattern, description) VALUES ('FR-Regex-Hybrid', '(?i)\bHYBRID\b', 'Détecte le tag HYBRID (Bluray hybride — mix de plusieurs sources Bluray pour obtenir la meilleure piste vidéo/audio). Source haut de gamme reconnue sur la scène FR, fréquente en UHD BluRay.');
INSERT INTO regular_expressions (name, pattern, description) VALUES ('FR-Regex-MULTI', '(?i)(?:MULTITRUEFRENCH|MULTI[ ._-]?TRUEFRENCH|MULTI[ ._-]?FRENCH)|\b(MULTI)\b', 'Détecte le tag MULTI et variantes collées (MULTITRUEFRENCH, MULTI.FRENCH). Insensible à la casse. Évite MultiVerse via limite de mot sur MULTI seul.');
INSERT INTO regular_expressions (name, pattern, description) VALUES ('FR-Regex-Streamers-Premium', '(?:\b(?:NF|Netflix)\b|\b(?:AMZN|(?:AMAZON)(?=\s*.(?:WEB-?DL|WEBRIP)))\b|\b(?:dsnp|dsny(?:p)?|disney\+)\s*\b|\b(?:ATVP|ATV|APTV|Apple TV\+)\s*\b|\b(?:HMAX|HBOM|(?:HBO[ ._-]?MAX)(?=\s*.(?:WEB-?DL|WEBRIP)))\b|\b(?:(?<!hbo[ ._-])max)\b(?=[ ._-]web[ ._-]?(?:dl|rip)\b)|\[(?:MAX)\b|\b(?:MAX)\]|\b(?:PMTP|Paramount Plus)\b)', 'Regroupe les motifs « streamers premium » (Netflix, Prime Video, Disney+, Apple TV+, HBO Max / Max, Paramount+) en une seule regex projet — évite huit motifs séparés. Comportement repris des modèles Dictionarry d’origine.');
INSERT INTO regular_expressions (name, pattern, description) VALUES ('FR-Regex-Streamers-Standard', '(?i)(?:\bnow\b[ ._-]web[ ._-]?(?:dl|rip)?\b|\[(?:NOW)\b|\b(?:NOW)\]|\b(?:C(?:runchy)?[ .-]?R(?:oll)?)\b|\b(?:it|itunes)\b(?=[ ._-]web[ ._-]?(?:dl|rip)\b)|\[(?:iT)\b|\b(?:iT)\])', 'Regroupe NOW / Sky, Crunchyroll et iTunes (WEB) en une seule regex projet — remplace 5 fichiers séparés. Insensible à la casse sur l’ensemble du motif pour coller aux tags fréquents (NOW.WEB-DL).');
INSERT INTO regular_expressions (name, pattern, description) VALUES ('FR-Regex-VF2', '(?i)\b(VF2|VFQ|VOQ)\b', 'Détecte les tags audio VF2, VFQ ou VOQ (Québec / québécois, ex. releases QTZ « Version originale québécoise »). Adapté aux tags VF2/VFQ/VOQ de la scène française privée.');
INSERT INTO regular_expressions (name, pattern, description) VALUES ('FR-Regex-VFF', '(?i)(?:MULTITRUEFRENCH|MULTI[ ._-]?TRUEFRENCH|MULTI[ ._-]?FRENCH)|\b(VFF|TRUEFRENCH|VFI|VOF|VFB|VF(?!Q|2)|FRENCH|FRANCAIS|FRANÇAIS)\b', 'Détecte les tags audio français hors VFQ/VF2/VOQ (VFF, TRUEFRENCH, MULTITRUEFRENCH, MULTI.FRENCH, FRENCH, FRANCAIS, VFI, VOF, VFB, VF générique). VOQ via FR-Regex-VF2.');
INSERT INTO regular_expressions (name, pattern, description) VALUES ('FR-Regex-VOSTFR', '(?i)\b(VOST[ ._-]?FR|SUBFRENCH|FANSUB|FASTSUB)\b', 'Détecte les variantes de sous-titres FR sur VO (VOSTFR, VOST-FR, SUBFRENCH, FANSUB, FASTSUB). Repli langue accepté quand aucun doublage MULTI / VFF / VF2 n''est disponible.');
INSERT INTO regular_expressions (name, pattern, description) VALUES ('FR-Repack-2', '(?i)\b(?:(?:proper|repack)2\b|(?:real[\s._-]+){1,2}proper\b)', 'Deuxième itération PROPER/REPACK ou chaîne REAL…PROPER (hors suffixe 3, réservé à FR-Repack-3).');
INSERT INTO regular_expressions (name, pattern, description) VALUES ('FR-Repack-3', '(?i)\b(?:proper|repack)3\b', 'Troisième itération PROPER/REPACK — correction la plus « profonde » signalée dans le titre.');
INSERT INTO regular_expressions (name, pattern, description) VALUES ('FR-Repack', '(?i)\b(?!(?:proper|repack)[23]\b|(?:real[\s._-]+){1,2}proper\b)(?:real[\s._-]+){0,2}(?:repack|rerip|proper)[123]?\b', 'PROPER / REPACK / RERIP / REAL simple (hors itérations 2–3 et hors chaîne REAL…PROPER, couvertes par FR-Repack-2 / FR-Repack-3).');
INSERT INTO regular_expressions (name, pattern, description) VALUES ('FR-Tier-01', '(?i)\b(BOUBA|NEOSTARK|N3ZUKO|J4CK|MAXADONF|Maxadonf|D4RK|R3MiX|RAPTOR|Themouche|SUPERFLU|LaFistiniere|R3DUCT0|SHADOW|Shadow|OPTIMUM|ESPER|D5T0)\b', 'Palier 01 (longue traîne — haut) — BOUBA + encodeurs G2. Teams documentées → FR-Team-.');
INSERT INTO regular_expressions (name, pattern, description) VALUES ('FR-Tier-02', '(?i)\b(TLC|DN55|Dramas[ ._]?For[ ._]?Ever|DFE|KAF|NYX|raf66|Raf66|HazzAnim|prem|FIST|Fist|Macolive|GISMO65|ZEKEY|FIRESOUL64|Firesoul64|PokemonFansub|FANKAI|PiCKLES|KPORAL|ACKER|TG7|STORiES|RiFiFi|DRIVE|AuriA|STIF|FUTE69|higgsboson|Alicia|BOONA33|RedROses|jdjo69|Luju|hyhyho|Chachou6768|TTK|Kaoru111|PARISTOCAT|tlub|ztgold|UKDHD|ZatNik07|Dixcents|Sicario|XSHD|DELIRIUS)\b', 'Palier 02 (longue traîne — bas) — G3/G4, séries WEB (ex. DELIRIUS) et suivis. Sous FR-Team- et FR-Tier-01.');
INSERT INTO regular_expressions (name, pattern, description) VALUES ('Full Disc', '(?i)^(?!.*\b((?<!HD[._ -]|HD)DVD|BDRip|MKV|XviD|WMV|d3g|BDREMUX|REMUX|^(?=.*1080p)(?=.*HEVC)|[xh][-_. ]?26[45]|German.*DL|((?<=\d{4}).*German.*(DL)?)(?=.*\b(AVC|HEVC|VC[-_. ]?1|MVC|MPEG[-_. ]?2)\b))\b)(((?=.*\b(Blu[-_. ]?ray|BD|HD[-_. ]?DVD)\b)(?=.*\b(AVC|HEVC|VC[-_. ]?1|MVC|MPEG[-_. ]?2|BDMV|ISO)\b))|^((?=.*\b(^((?=.*\b((.*_)?COMPLETE.*|Dis[ck])\b)(?=.*(Blu[-_. ]?ray|HD[-_. ]?DVD)))|3D[-_. ]?BD|BR[-_. ]?DISK|Full[-_. ]?Blu[-_. ]?ray|^((?=.*((BD|UHD)[-_. ]?(25|50|66|100|ISO)))))))).*|(?:DVD9|DVD5|NTSC|PAL|VOB IFO|VC-1|AVC|MPEG-2|\bCOMPLETE[-.\s]?(?:UHD[-.\s])?BLU[-.\s]?RAY\b|\bCOMPLETE BLURAY\b|\bBR-Disk\b)', 'Repère une release « Full Disc » : copie exhaustive d’un média physique (DVD, Blu-ray/UHD…) conservant dossiers menus, bonus, pistes et structure d’origine (souvent ISO / BDMV / dossier BR-DISK). Ce motif est très strict : il évite faux …');
INSERT INTO regular_expressions (name, pattern, description) VALUES ('HDR', '\b(HDR)\b', 'Champ lexical HDR ouvert (attrape « HDR », etc.) encore ambigu jusqu’aux variantes Dolby/HDR10+ ultérieurement filtrées en aval par CF plus fines (HDR10, HDR10+, exclusions SDR…).');
INSERT INTO regular_expressions (name, pattern, description) VALUES ('HDR10+', '\bHDR10.?(\+|P(lus)?\b)', 'HDR10+ (« HDR10 PLUS » dynamique avec metadata additionnelles) détecté quand HDR10 est suivi d’un suffixe explicitant + / Plus/P selon règle TRaSH-Dictionarry.');
INSERT INTO regular_expressions (name, pattern, description) VALUES ('HDR10', '\bHDR10(?!\+|Plus)\b', 'HDR10 strict (sans suffixe + / Plus réservé à HDR10+). Pourquoi : éviter de confondre HDR10 et HDR10+ dans le scoring.');
INSERT INTO regular_expressions (name, pattern, description) VALUES ('HLG', '\b(HLG)\b', 'HLG (« Hybrid Log-Gamma ») : HDR broadcast télé / IPTV. Utilisée pour détections spéciales ou exclusions selon vos profils domestiques (« pas de HDR broadcast TV caps » ).');
INSERT INTO regular_expressions (name, pattern, description) VALUES ('IMAX Enhanced', '(?i)^(?=.*\b((DSNP|Disney\+|BC|B?CORE)(?=.?web.?(dl|rip)\b)))(?=.*\b((?<!NON.?)IMAX(.?Enhanced)?)\b)', 'IMAX Enhanced pour WEB issus de Disney+ (tags DSNP, Disney+, etc.) ou Bravia Core (BC / CORE), avec mention IMAX (suffixe Enhanced optionnel), en excluant les variantes précédées de « NON‑IMAX » selon lookahead du motif projet.');
INSERT INTO regular_expressions (name, pattern, description) VALUES ('IMAX', '\b((?<!NON.?)IMAX)\b', 'Repère IMAX (expérience géant écran augmenté hors tag « NON‑IMAX ») et variantes Enhanced basiques encore taguées IMAX générique hors regex IMAX Enhanced dédiée (Disney+/BC).');
INSERT INTO regular_expressions (name, pattern, description) VALUES ('Opus', '\bOPUS(\b|\d)(?!.*[ ._-](\d{3,4}p))', 'Opus dans le titre, avec lookahead négatif empêchant qu’un segment XXXp (résolution) apparaisse plus loin dans la même chaîne après OPUS — ancien garde‑fou Dictionarry contre les collisions avec des noms de groupe ou artefacts de titre m…');
INSERT INTO regular_expressions (name, pattern, description) VALUES ('PCM', '(?i)\b(l?)PCM(\b|\d)', 'LPCM / PCM (« PCM », LPCM) : audio PCM linéaire non compressé, souvent sur captures télé ou master Blu-ray hors Dolby bitstream (Dolby Digital). Insensible à la casse (lpcm accepté par le motif).');
INSERT INTO regular_expressions (name, pattern, description) VALUES ('PQ', '\b(PQ|PQ10)\b', 'PQ (« Perceptual Quantizer ») : signal HDR statique SMPTE ST2084 associé généralement HDR10/HDR10+ metadata — utile motifs « Basic HDR PQ detection » composites Dictionarry.');
INSERT INTO regular_expressions (name, pattern, description) VALUES ('Remux', '(?i)Remux', 'Le mot Remux (insensible à la casse). Indique conteneurs sans ré-encodage (« copie quasi bit-à-bit » depuis Blu-ray / DVD ). Séparée des filtres Full Disc puisque vos profils peuvent décider différemment d’accueillir un Remux 1080p vs tr…');
INSERT INTO regular_expressions (name, pattern, description) VALUES ('SDR', '\b(SDR)\b', 'Détection explicite de la mention « SDR » sur le titre : Gamme dynamique standard (« Standard Dynamic Range »), soit pas HDR — utile pour fiabiliser ou filtrer des UHD/remux où l’éditeur indique noir sur blanc une version sans extension …');
INSERT INTO regular_expressions (name, pattern, description) VALUES ('Theatrical Edition', '(?i)^(.*?)(\d{4})(.*?)\b(theatrical)\b', 'Mention « Theatrical » (cut ciné standard) doit apparaître après l’année sur quatre chiffres pour éviter les faux positifs lorsque ce mot fait partie du titre marchand réel placé avant l’année.');
INSERT INTO regular_expressions (name, pattern, description) VALUES ('TrueHD', 'True[ .-]?HD[ .-]?', 'Dolby TrueHD (« True‑HD » selon typo) — audio sans perte Dolby issu très souvent Blu-ray/remux téléchargées privées ; la piste immersive Atmos est généralement gérée séparément par le CF Atmos via FR-Regex-Atmos-Bundle.');
INSERT INTO regular_expressions (name, pattern, description) VALUES ('UHD Bluray', '\bUHD[-_.\s]?Blu[-]?Ray\b', 'Détecte Ultra HD Blu-ray écrit sous formes UHD Bluray, UHD Blu-ray avec séparateurs variés (trait d’union, espace, point ou soulignement entre UHD et Bluray/BluRay). Sert aux chaînes de scoring « source UHD annoncée » dans votre base.');
INSERT INTO regular_expressions (name, pattern, description) VALUES ('Upscaled', '(Up[-\.\s]?scale|Re[-\.\s]?Grade|\bAIUS\b|AI[-\.\s]?enhanced)', 'Repère tout marqueur d’upscale artisanal, regrade colorimétrique agressif, ou jargon « AI enhanced / AIUS » évocateur sur un titre indexer (à bannir quand vos profils recherchent un master natif fidèle).');
INSERT INTO regular_expressions (name, pattern, description) VALUES ('VP9', '\b(VP9)\b', 'VP9 : codec vidéo ouvert développé par Google (famille ouverte WebM/streaming léger sans redevances). Souvent utilisé hors écosystèmes trackers privés ciblés par vos profils HEVC.');
INSERT INTO regular_expressions (name, pattern, description) VALUES ('VVC', '(?<=^|[\s.-])VVC\b', 'VVC (H.266 / MPEG-I partie 8, « Versatile Video Coding ») : codec de très haute efficacité encore rare sur cercles français ; léger bonus expérimental quand vos lecteurs assurent décodage matériel.');
INSERT INTO regular_expressions (name, pattern, description) VALUES ('Xvid', '(?i)[-. ]Xvid', 'Ancien codec vidéo Xvid, dérivée grand public du MPEG-4 Partie 2 (ASP). Encore présent sur vieux téléchargements DVDRip / télé SD ; peu compatible avec vos objectifs HDR 1080p/4K (« -500 » CF classique lorsqu’AFFICHÉ encore sur lignes tr…');
INSERT INTO regular_expressions (name, pattern, description) VALUES ('h265', '(?i)h\s*\.?\s*265', 'Détecte la désignation H.265 / H265 tolérante aux espacements autour du point (alternative graphique commune à « x265 »). Codec HEVC : meilleure efficacité que AVC à débit équivalent ; très présent pour UHD HDR sur vos trackers français.');
INSERT INTO regular_expressions (name, pattern, description) VALUES ('AMEN', '(?i)(?<=^|[\s.-])AMEN\b', 'Groupe AMEN — WEB 2160p compact (DV/HDR10+). Utilisé par FR-Team-AMEN.');
INSERT INTO regular_expressions (name, pattern, description) VALUES ('BONBON', '(?i)(?<=^|[\s.-])BONBON\b', 'Groupe BONBON — 2160p 4KLight / WEBRip compact (~2,5–5 Go). Utilisé par FR-Team-BONBON.');
INSERT INTO regular_expressions (name, pattern, description) VALUES ('BOUC', '(?i)(?<=^|[\s.-])BOUC\b', 'Groupe BOUC — WEB 2160p premium (DV/HDR10+, MULTI, ~9–20 Go). FR-Team-BOUC.');
INSERT INTO regular_expressions (name, pattern, description) VALUES ('ENIGMA', '(?i)(?<=^|[\s.-])ENIGMA\b', 'Groupe ENIGMA — WEB 1080p/2160p (H264/H265, EAC3, HDR10 en 4K). MULTI VFF/VF2/VFQ/VFI, nombreuses sorties VFQ et EXCLU sur certains trackers. Suffixe -ENIGMA ou -Enigma.');
INSERT INTO regular_expressions (name, pattern, description) VALUES ('FW', '(?i)(?<=^|[\s.-])(?:FORWARD|FW)\b', 'Groupe Forward (FW / FORWARD) — WEB 2160p catalogue (~9–20 Go). FR-Team-FW.');
INSERT INTO regular_expressions (name, pattern, description) VALUES ('HYPERION', '(?i)(?<=^|[\s.-])HYPERION\b', 'Groupe HYPERION — quasi tout en BluRay/UHD Remux (TrueHD Atmos, DV/HDR10+), ~25–109 Go. Quelques WEB 2160p. Reconnu par FR-Team-HYPERION ; Remux -999999 sur profils stricts.');
INSERT INTO regular_expressions (name, pattern, description) VALUES ('OZEF', '(?i)(?<=^|[\s.-])OZEF\b', 'Groupe OZEF — BluRay/UHD REMUX (TrueHD, DTS-HD MA). Reconnu par FR-Team-OZEF ; nos profils excluent Remux (-999999) → jamais retenu en pratique.');
INSERT INTO regular_expressions (name, pattern, description) VALUES ('PopHD', '(?i)(?<=^|[\s.-])PopHD\b', 'Groupe PopHD — 1080p BluRay/HDLight x264 (~2–4 Go), MULTI VFF/VF2. FR-Team-PopHD.');
INSERT INTO regular_expressions (name, pattern, description) VALUES ('QTZ', '(?i)(?<=^|[\s.-])QTZ\b', 'Groupe QTZ — référence 4KLight Bluray (qualité / taille). Utilisé par FR-Team-QTZ.');
INSERT INTO regular_expressions (name, pattern, description) VALUES ('SUPPLY', '(?i)(?<=^|[\s.-])SUPPLY\b', 'Groupe SUPPLY — WEB 2160p premium (H265, DV/HDR10+, Atmos, ~10–25 Go). FR-Team-SUPPLY.');
INSERT INTO regular_expressions (name, pattern, description) VALUES ('Slay3R', '(?i)(?<=^|[\s.-])Slay3R\b', 'Groupe Slay3R — WEB 2160p volume / exclus. Utilisé par FR-Team-Slay3R.');
INSERT INTO regular_expressions (name, pattern, description) VALUES ('TFA', '(?i)(?<=^|[\s.-])TFA\b', 'Groupe TFA — WEB 2160p MULTI (VFF/VF2), HDR/DV, ~10–18 Go. Utilisé par FR-Team-TFA.');
INSERT INTO regular_expressions (name, pattern, description) VALUES ('THESYNDiCATE', '(?i)(?<=^|[\s.-])THESYNDiCATE\b', 'Groupe THESYNDiCATE — WEB 2160p H265/x265 (~8–22 Go). Les sorties AV1 sont proscrites par nos profils.');
INSERT INTO regular_expressions (name, pattern, description) VALUES ('TOXIC', '(?i)(?<=^|[\s.-])TOXIC\b', 'Groupe TOXIC — 1080p BluRay/WEB HDLight (x264, AC3/EAC3), ~2–3,5 Go. MULTI VFF/VFQ/VFI, VFF, VOSTFR.');
INSERT INTO regular_expressions (name, pattern, description) VALUES ('TyHD', '(?i)(?<=^|[\s.-])TyHD\b', 'Groupe TyHD — WEB/WEBRip 2160p HEVC compact. Utilisé par FR-Team-TyHD.');
INSERT INTO regular_expressions (name, pattern, description) VALUES ('x264', '^(?!.*(?i:remux)).*([xh](\.?264)|DVDRip)', 'x264 / H.264 (AVC) : encodeur open-source très répandu pour fichiers au format MPEG-4 AVC. Le motif couvre x264, h264, H.264, ainsi que DVDRip (anciens téléchargements DVD → AVC SD) tout en excluant explicitement tout titre contenant « r…');
INSERT INTO regular_expressions (name, pattern, description) VALUES ('x265', '^(?!.*(?i:remux))(?=.*([x]\s?(\.?265)\b|HEVC|\bDS4K\b)).*$', 'Encodeur / mention x265, HEVC ou encore balise DS4K dans le titre, hors lignes comportant REMUX (« lookahead » négatif avant correspondance du motif, selon ancien guide Dictionarry) pour isoler pipelines transcodés légers domestiques fra…');
